#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  uint16_t x;
  uint16_t y;
};

static inline float half_to_float(uint16_t h) {
  const uint16_t h_exp = (h & 0x7C00u);
  const uint16_t h_sig = (h & 0x03FFu);
  const uint32_t f_sgn = ((uint32_t)h & 0x8000u) << 16;

  uint32_t f_exp, f_sig;
  if (h_exp == 0) {
    if (h_sig == 0) {
      f_exp = 0;
      f_sig = 0;
    } else {
      int shift = 0;
      uint16_t sig = h_sig;
      while ((sig & 0x0400u) == 0) {
        sig <<= 1;
        ++shift;
      }
      sig &= 0x03FFu;
      f_exp = (uint32_t)(127 - 15 - shift) << 23;
      f_sig = (uint32_t)sig << 13;
    }
  } else if (h_exp == 0x7C00u) {
    f_exp = 0xFFu << 23;
    f_sig = (uint32_t)h_sig << 13;
  } else {
    f_exp = (uint32_t)(((h_exp >> 10) + (127 - 15)) & 0xFFu) << 23;
    f_sig = (uint32_t)h_sig << 13;
  }

  uint32_t f = f_sgn | f_exp | f_sig;
  float out;
  std::memcpy(&out, &f, sizeof(out));
  return out;
}

static inline uint16_t float_to_half(float f) {
  uint32_t x;
  std::memcpy(&x, &f, sizeof(x));

  uint16_t sign = (uint16_t)((x >> 16) & 0x8000u);
  int exp = (int)((x >> 23) & 0xFFu) - 127 + 15;
  uint32_t mant = x & 0x7FFFFFu;

  if (exp <= 0) {
    if (exp < -10) return sign;
    mant |= 0x800000u;
    uint32_t t = mant >> (14 - exp);
    return (uint16_t)(sign | t);
  } else if (exp >= 31) {
    return (uint16_t)(sign | 0x7C00u);
  } else {
    return (uint16_t)(sign | ((uint16_t)exp << 10) | (uint16_t)(mant >> 13));
  }
}

