static inline uint16_t float_to_half(float f) {
  union {
    float f;
    uint32_t u;
  } v{f};

  uint32_t sign = (v.u >> 16) & 0x8000u;
  uint32_t mantissa = v.u & 0x007fffffu;
  int32_t exp = static_cast<int32_t>((v.u >> 23) & 0xffu) - 127 + 15;

  if (exp <= 0) {
    if (exp < -10) return static_cast<uint16_t>(sign);
    mantissa = (mantissa | 0x00800000u) >> (1 - exp);
    return static_cast<uint16_t>(sign | ((mantissa + 0x00001000u) >> 13));
  }
  if (exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  return static_cast<uint16_t>(sign | (static_cast<uint32_t>(exp) << 10) |
                               ((mantissa + 0x00001000u) >> 13));
}

static inline float half_to_float(uint16_t h) {
  uint32_t sign = (static_cast<uint32_t>(h & 0x8000u)) << 16;
  uint32_t exp = (h >> 10) & 0x1fu;
  uint32_t mantissa = h & 0x03ffu;

  uint32_t out;
  if (exp == 0) {
    if (mantissa == 0) {
      out = sign;
    } else {
      exp = 1;
      while ((mantissa & 0x0400u) == 0) {
        mantissa <<= 1;
        --exp;
      }
      mantissa &= 0x03ffu;
      out = sign | ((exp + (127 - 15)) << 23) | (mantissa << 13);
    }
  } else if (exp == 31) {
    out = sign | 0x7f800000u | (mantissa << 13);
  } else {
    out = sign | ((exp + (127 - 15)) << 23) | (mantissa << 13);
  }

  union {
    uint32_t u;
    float f;
  } v{out};
  return v.f;
}

static inline uint16_t half2_low(const half2& h) {
  return static_cast<uint16_t>(h.storage & 0xffffu);
}
static inline uint16_t half2_high(const half2& h) {
  return static_cast<uint16_t>((h.storage >> 16) & 0xffffu);
}
static inline half2 make_half2(uint16_t lo, uint16_t hi) {
  half2 h;
  h.storage = static_cast<uint32_t>(lo) | (static_cast<uint32_t>(hi) << 16);
  return h;
}

