#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  uint16_t x;
  uint16_t y;
};

static inline float half_to_float(uint16_t h) {
  uint32_t sign = (uint32_t)(h & 0x8000u) << 16;
  uint32_t exp = (h >> 10) & 0x1Fu;
  uint32_t mant = h & 0x03FFu;
  uint32_t fbits;

  if (exp == 0) {
    if (mant == 0) {
      fbits = sign;
    } else {
      exp = 1;
      while ((mant & 0x0400u) == 0) {
        mant <<= 1;
        --exp;
      }
      mant &= 0x03FFu;
      exp = exp + (127 - 15);
      fbits = sign | (exp << 23) | (mant << 13);
    }
  } else if (exp == 31) {
    fbits = sign | 0x7F800000u | (mant << 13);
  } else {
    exp = exp + (127 - 15);
    fbits = sign | (exp << 23) | (mant << 13);
  }

  float out;
  std::memcpy(&out, &fbits, sizeof(out));
  return out;
}

static inline uint16_t float_to_half(float f) {
  uint32_t bits;
  std::memcpy(&bits, &f, sizeof(bits));

  uint16_t sign = (uint16_t)((bits >> 16) & 0x8000u);
  int32_t exp = (int32_t)((bits >> 23) & 0xFFu) - 127 + 15;
  uint32_t mant = bits & 0x7FFFFFu;

  if (exp <= 0) {
    if (exp < -10) return sign;
    mant = (mant | 0x800000u) >> (1 - exp);
    return (uint16_t)(sign | ((mant + 0x1000u) >> 13));
  }
  if (exp >= 31) {
    return (uint16_t)(sign | 0x7C00u);
  }
  return (uint16_t)(sign | ((uint16_t)exp << 10) | (uint16_t)((mant + 0x1000u) >> 13));
}

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline half2 conv_int<half2>(const int i) {
  const uint16_t h = float_to_half((float)i);
  return half2{h, h};
}

template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  half2 out;
  out.x = float_to_half(half_to_float(a.x) * half_to_float(b.x) + half_to_float(c.x));
  out.y = float_to_half(half_to_float(a.y) * half_to_float(b.y) + half_to_float(c.y));
  return out;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return a.x == b.x && a.y == b.y;
}

template <class T, int blockdim, unsigned int granularity, unsigned int fusion_degree,
          unsigned int compute_iterations, bool TemperateUnroll>
static void benchmark_func(T seed, T* g_data, int gridDimX) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const int stride = (int)blockSize;
  const int big_stride = gridDimX * (int)blockSize * (int)granularity;

#pragma omp parallel for collapse(2) schedule(static)
  for (int blockIdx = 0; blockIdx < gridDimX; ++blockIdx) {
    for (int threadIdx = 0; threadIdx < (int)blockSize; ++threadIdx) {
      int idx = blockIdx * (int)blockSize * (int)granularity + threadIdx;

      T tmps[granularity];
      for (unsigned int k = 0; k < fusion_degree; k++) {
        for (unsigned int j = 0; j < granularity; j++) {
          tmps[j] = g_data[idx + (int)j * stride + (int)k * big_stride];
          for (unsigned int i = 0; i < compute_iterations; i++) {
            tmps[j] = mad(tmps[j], tmps[j], seed);
          }
        }

        T sum = conv_int<T>(0);
        for (unsigned int j = 0; j < granularity; j += 2) {
          sum = mad(tmps[j], tmps[j + 1], sum);
        }

        if (equal(sum, conv_int<T>(-1))) {
          g_data[idx + (int)k * big_stride] = sum;
        }
      }
    }
  }
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS = (int)(reduced_grid_size / BLOCK_SIZE);

  benchmark_func<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      (short)1, (short*)cd, TOTAL_REDUCED_BLOCKS);
}

template <unsigned int compute_iterations>
static void runbench(double* cd, long size, bool doHalfs) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int BLOCK_SIZE = 256;
  const int TOTAL_BLOCKS = (int)(compute_grid_size / BLOCK_SIZE);
  const long long computations =
      (ELEMENTS_PER_THREAD * (long long)compute_grid_size +
       (2 * ELEMENTS_PER_THREAD * compute_iterations) * (long long)compute_grid_size) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  auto t0 = std::chrono::high_resolution_clock::now();
  benchmark_func<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false>(
      1.0f, (float*)cd, TOTAL_BLOCKS);
  auto t1 = std::chrono::high_resolution_clock::now();
  float kernel_time_mad_sp =
      (float)std::chrono::duration<double, std::milli>(t1 - t0).count();

  t0 = std::chrono::high_resolution_clock::now();
  benchmark_func<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false>(
      1.0, cd, TOTAL_BLOCKS);
  t1 = std::chrono::high_resolution_clock::now();
  float kernel_time_mad_dp =
      (float)std::chrono::duration<double, std::milli>(t1 - t0).count();

  float kernel_time_mad_hp = 0.f;
  if (doHalfs) {
    half2 h_ones{(uint16_t)15360u, (uint16_t)15360u};
    t0 = std::chrono::high_resolution_clock::now();
    benchmark_func<half2, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, false>(
        h_ones, (half2*)cd, TOTAL_BLOCKS);
    t1 = std::chrono::high_resolution_clock::now();
    kernel_time_mad_hp =
        (float)std::chrono::duration<double, std::milli>(t1 - t0).count();
  }

  t0 = std::chrono::high_resolution_clock::now();
  benchmark_func<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations, true>(
      1, (int*)cd, TOTAL_BLOCKS);
  t1 = std::chrono::high_resolution_clock::now();
  float kernel_time_mad_int =
      (float)std::chrono::duration<double, std::milli>(t1 - t0).count();

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

